from flask import Flask, request, jsonify
from pymongo import MongoClient, ASCENDING, DESCENDING
from pymongo.errors import DuplicateKeyError
from bson import ObjectId
from datetime import datetime
import os

app = Flask(__name__)

MONGO_URI = os.getenv("MONGO_URI", "mongodb://localhost:27017")
DB_NAME = os.getenv("MONGO_DB_NAME", "content_management_system")

client = MongoClient(MONGO_URI)
db = client[DB_NAME]

users_collection = db["user_profiles"]
documents_collection = db["documents"]

users_collection.create_index([("email", ASCENDING)], unique=True)
users_collection.create_index([("username", ASCENDING)], unique=True)
documents_collection.create_index([("author_id", ASCENDING)])
documents_collection.create_index([("tags", ASCENDING)])
documents_collection.create_index([("status", ASCENDING), ("created_at", DESCENDING)])


def serialize_value(value):
    if isinstance(value, ObjectId):
        return str(value)
    if isinstance(value, datetime):
        return value.isoformat()
    if isinstance(value, list):
        return [serialize_value(v) for v in value]
    if isinstance(value, dict):
        return {k: serialize_value(v) for k, v in value.items()}
    return value


def serialize_document(doc):
    return serialize_value(doc)


def parse_object_id(value, field_name="id"):
    try:
        return ObjectId(value)
    except Exception:
        raise ValueError(f"Invalid {field_name}")


