@app.route("/documents/search", methods=["POST"])
def advanced_document_query():
    data = request.get_json(silent=True) or {}
    query = {}

    if "status" in data:
        query["status"] = data["status"]

    if "tags" in data and isinstance(data["tags"], list) and data["tags"]:
        query["tags"] = {"$in": data["tags"]}

    if "author_ids" in data and isinstance(data["author_ids"], list) and data["author_ids"]:
        try:
            query["author_id"] = {"$in": [parse_object_id(v, "author_ids") for v in data["author_ids"]]}
        except ValueError as e:
            return jsonify({"error": str(e)}), 400

    if "created_after" in data or "created_before" in data:
        query["created_at"] = {}
        if "created_after" in data:
            query["created_at"]["$gte"] = datetime.fromisoformat(data["created_after"])
        if "created_before" in data:
            query["created_at"]["$lte"] = datetime.fromisoformat(data["created_before"])

    if "text" in data and data["text"]:
        query["$or"] = [
            {"title": {"$regex": data["text"], "$options": "i"}},
            {"content": {"$regex": data["text"], "$options": "i"}},
            {"summary": {"$regex": data["text"], "$options": "i"}},
        ]

    sort_by = data.get("sort_by", "created_at")
    sort_order = DESCENDING if data.get("sort_order", "desc").lower() == "desc" else ASCENDING
    limit = min(int(data.get("limit", 20)), 100)
    skip = max(int(data.get("skip", 0)), 0)

    documents = list(
        documents_collection.find(query)
        .sort(sort_by, sort_order)
        .skip(skip)
        .limit(limit)
    )
    return jsonify([serialize_document(doc) for doc in documents]), 200


@app.route("/analytics/documents/by-status", methods=["GET"])
def aggregate_documents_by_status():
    pipeline = [
        {
            "$group": {
                "_id": "$status",
                "count": {"$sum": 1},
                "latest_created_at": {"$max": "$created_at"},
            }
        },
        {"$sort": {"count": -1}},
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify([serialize_document(result) for result in results]), 200


