@app.route("/analytics/content-summary", methods=["GET"])
def aggregate_content_summary():
    pipeline = [
        {
            "$project": {
                "status": 1,
                "tag_count": {"$size": {"$ifNull": ["$tags", []]}},
                "content_length": {"$strLenCP": {"$ifNull": ["$content", ""]}},
            }
        },
        {
            "$group": {
                "_id": "$status",
                "documents": {"$sum": 1},
                "avg_tag_count": {"$avg": "$tag_count"},
                "avg_content_length": {"$avg": "$content_length"},
                "max_content_length": {"$max": "$content_length"},
            }
        },
        {"$sort": {"documents": -1}},
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify([serialize_document(result) for result in results]), 200


